// // Asynchronous reset and write enable functionality. On the falling edge of the clock, if the reset signal is high, the output q is set to zero. If reset is low and the write enable (wren) signal is high, the output q takes on the value of the input data. Otherwise, the output retains its previous value.
module top_module(clock, reset, wren, data, q);input clock, reset, wren;
	input  [31:0] data;
	output reg [31:0] q;


	always @(posedge clock)
	if (reset==1'b1)
		q = 32'b0;
	else if(wren == 1'b1)
		q = data;

endmodule
